use std::collections::VecDeque;

pub fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    if m == 0 {
        return 0;
    }
    let n = grid[0].len();
    let mut visited = vec![vec![false; n]; m];
    let directions = [(0, 1), (0, -1), (1, 0), (-1, 0)];
    let mut count = 0;

    for i in 0..m {
        for j in 0..n {
            if grid[i][j] > 0 && !visited[i][j] {
                let mut queue = VecDeque::new();
                queue.push_back((i, j));
                visited[i][j] = true;
                let mut sum = 0;
                while let Some((x, y)) = queue.pop_front() {
                    sum += grid[x][y];
                    for (dx, dy) in directions.iter() {
                        let nx = x as i32 + dx;
                        let ny = y as i32 + dy;
                        if nx >= 0 && nx < m as i32 && ny >= 0 && ny < n as i32 {
                            let nx = nx as usize;
                            let ny = ny as usize;
                            if grid[nx][ny] > 0 && !visited[nx][ny] {
                                visited[nx][ny] = true;
                                queue.push_back((nx, ny));
                            }
                        }
                    }
                }
                if sum % k == 0 {
                    count += 1;
                }
            }
        }
    }
    count
}
